const GHTOKEN=$env.GITHUB_TOKEN,OWNER_CHAT=$env.OWNER_CHAT,BALE=$env.BALE_BOT_TOKEN;
const CLAUDE_BRIDGE='http://host.docker.internal:8787/v1/messages';
const req=(o)=>this.helpers.httpRequest(o);
const tUrl=(p)=>'https://api.trello.com/1/'+p+(p.includes('?')?'&':'?')+'key='+TK+'&token='+TT;
const tGet=async(p)=>{try{return await req({method:'GET',url:tUrl(p),json:true});}catch(e){return [];}};
const tPost=async(p)=>req({method:'POST',url:tUrl(p),json:true});
const tPut=async(p)=>req({method:'PUT',url:tUrl(p),json:true});
const tDel=async(p)=>{try{return await req({method:'DELETE',url:tUrl(p),json:true});}catch(e){return null;}};
const bale=async(chat,text)=>{try{await req({method:'POST',url:'https://tapi.bale.ai/bot'+BALE+'/sendMessage',body:JSON.stringify({chat_id:chat,text}),headers:{'content-type':'application/json'},json:false});}catch(e){}};
const claude=async(prompt,mt)=>{const r=await req({method:'POST',url:CLAUDE_BRIDGE,body:JSON.stringify({model:'claude-opus-4-8',max_tokens:mt||3000,messages:[{role:'user',content:prompt}]}),headers:{'content-type':'application/json'},json:false});const j=typeof r==='string'?JSON.parse(r):r;return (j.content&&j.content[0]&&j.content[0].text)||'';};
const strip=(s)=>String(s||'').replace(/```json|```/g,'').trim();
const jparse=(t)=>{let s=strip(t);try{return JSON.parse(s);}catch(e){}let a=s.indexOf('{'),b=s.lastIndexOf('}');if(a>=0&&b>a){try{return JSON.parse(s.slice(a,b+1));}catch(e){}}let c=s.indexOf('['),d=s.lastIndexOf(']');if(c>=0&&d>c){try{return JSON.parse(s.slice(c,d+1));}catch(e){}}return null;};
const enc=(s)=>Buffer.from(s||'','utf8').toString('base64');
const normRepo=(u)=>String(u||'').trim().replace(/\.git$/,'').replace(/^https?://github\.com//i,'').replace(/^github\.com//i,'');
const gh=async(method,path,body,raw)=>{const r=await req({method,url:'https://api.github.com'+path,headers:{Authorization:'Bearer '+GHTOKEN,Accept:raw?'application/vnd.github.raw+json':'application/vnd.github+json','User-Agent':'n8n-bot'},body:body?JSON.stringify(body):undefined,json:false});if(raw)return typeof r==='string'?r:JSON.stringify(r);try{return typeof r==='string'?JSON.parse(r):r;}catch(e){return r;}};
const meta=(d)=>{d=String(d||'');const g=(re)=>{const m=d.match(re);return m?m[1].trim():'';};return{repo:normRepo(g(/repo:\s*(\S+)/)),project:g(/project:\s*(.+)/),ref:g(/ref:\s*(\S+)/)};};
const trackOf=(name)=>{const m=String(name||'').match(/^\[(backend|frontend|mobile)\]/);return m?m[1]:'backend';};
const CI_YML="name: CI
on:
  pull_request:
    branches: [ develop ]
jobs:
  backend:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-python@v5
        with: { python-version: '3.12' }
      - name: backend tests
        run: |
          if [ -d backend ]; then
            cd backend
            pip install -r requirements.txt 2>/dev/null || pip install django djangorestframework pytest pytest-django
            python -m pytest -q
          else echo "no backend yet"; fi
  frontend:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-node@v4
        with: { node-version: '20' }
      - name: frontend tests
        run: |
          if [ -f frontend/package.json ]; then
            cd frontend
            npm ci || npm install
            npm test -- --watch=false --browsers=ChromeHeadless
          else echo "no frontend yet"; fi
  mobile:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-java@v4
        with: { distribution: 'temurin', java-version: '17' }
      - name: mobile tests
        run: |
          if [ -f mobile/gradlew ]; then
            cd mobile
            chmod +x gradlew && ./gradlew test
          else echo "no mobile yet"; fi
";

